module RefModule(
data  ,
clk    ,
reset ,
q     
);input data, clk, reset ; 
output q;
(*ASYNC_REG = "TRUE" *) reg q;
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ ( posedge clk or posedge reset or posedge dbg_halt) begin
  if (reset) begin
    q <= 1'b1;
  end  else begin
    q <= data;
  end
end
endmodule
